const transfers = flow.get('transfers') || {};
msg.payload = {
    status: 'ok',
    service: 'dsp-connector',
    transfers_count: Object.keys(transfers).length
};
msg.headers = { 'Content-Type': 'application/json' };
msg.statusCode = 200;
return msg;

// DSP-specific Prometheus text-format renderer. Counter families live in
// global.metrics.<family> so the Simulation tab's /metrics handler stays
// untouched. Cross-service counters in the same global object are fine —
// each tab renders only the families it owns.
const counters = global.get('metrics') || {};

function fmt(name, help, samples) {
    let out = '# HELP ' + name + ' ' + help + '\n';
    out += '# TYPE ' + name + ' counter\n';
    if (samples.length === 0) {
        out += name + ' 0\n';
        return out;
    }
    for (const [labels, value] of samples) {
        const labelStr = Object.entries(labels)
            .map(([k, v]) => k + '="' + v + '"').join(',');
        out += name + (labelStr ? '{' + labelStr + '}' : '') + ' ' + value + '\n';
    }
    return out;
}

let body = '';

const cat = counters.facis_dsp_catalogue_requests_total || {};
body += fmt('facis_dsp_catalogue_requests_total',
            'Total catalogue requests',
            Object.entries(cat).map(([_, v]) => [{}, v]));

const req = counters.facis_dsp_transfer_requests_total || {};
body += fmt('facis_dsp_transfer_requests_total',
            'Total transfer requests',
            Object.entries(req).map(([format, v]) => [{ format }, v]));

const comp = counters.facis_dsp_transfer_completions_total || {};
body += fmt('facis_dsp_transfer_completions_total',
            'Total completed transfers',
            Object.entries(comp).map(([_, v]) => [{}, v]));

const err = counters.facis_dsp_transfer_errors_total || {};
body += fmt('facis_dsp_transfer_errors_total',
            'Total transfer errors',
            Object.entries(err).map(([_, v]) => [{}, v]));

msg.payload = body;
msg.headers = { 'Content-Type': 'text/plain; version=0.0.4' };
msg.statusCode = 200;
return msg;

// msg.payload = { family: 'facis_dsp_...', label: '_total'|'<format>'|..., value?: number }
const m = global.get('metrics') || {};
const family = msg.payload && msg.payload.family;
const label = (msg.payload && msg.payload.label) || '_total';
const inc = (msg.payload && typeof msg.payload.value === 'number') ? msg.payload.value : 1;
if (!family) {
    node.warn('dsp.metric.inc: missing family');
    return null;
}
if (!m[family]) m[family] = {};
m[family][label] = (m[family][label] || 0) + inc;
global.set('metrics', m);
return null;
